### 3. `/root/.openclaw/workspace/cyberpress-platform/frontend/lib/react-query.ts`
React Query 配置文件，包含 QueryClient 和 Provider 组件

```typescript
'use client';

import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { ReactQueryDevtools } from '@tanstack/react-query-devtools';
import { useState, type ReactNode } from 'react';

export function ReactQueryProvider({ children }: { children: ReactNode }) {
  const [queryClient] = useState(
    () =>
      new QueryClient({
        defaultOptions: {
          queries: {
            staleTime: 60 * 1000, // 1 minute
            gcTime: 5 * 60 * 1000, // 5 minutes
            refetchOnWindowFocus: false,
            retry: 1,
          },
        },
      })
  );

  return (
    <QueryClientProvider client={queryClient}>
      {children}
      {process.env.NODE_ENV === 'development' && <ReactQueryDevtools initialIsOpen={false} />}
    </QueryClientProvider>
  );
}
```

### 4. `/root/.openclaw/workspace/cyberpress-platform/frontend/lib/hooks/use-posts.ts`
自定义 Hook，用于从 WordPress API 获取文章列表

```typescript
'use client';

import { useQuery } from '@tanstack/react-query';
import { wpClient, wpKeys } from '@/lib/wordpress/client';

export interface PostFilters {
  page?: number;
  perPage?: number;
  categories?: number[];
  tags?: number[];
  search?: string;
}

export function usePosts(filters: PostFilters = {}) {
  return useQuery({
    queryKey: wpKeys.posts(),
    queryFn: () => wpClient.getPosts(filters),
  });
}

export function usePost(id: number) {
  return useQuery({
    queryKey: wpKeys.post(id),
    queryFn: () => wpClient.getPost(id),
    enabled: !!id,
  });
}

export function usePostBySlug(slug: string) {
  return useQuery({
    queryKey: wpKeys.postBySlug(slug),
    queryFn: () => wpClient.getPostBySlug(slug),
    enabled: !!slug,
  });
}

export function useCategories() {
  return useQuery({
    queryKey: wpKeys.categories(),
    queryFn: () => wpClient.getCategories(),
  });
}

export function useTags() {
  return useQuery({
    queryKey: wpKeys.tags(),
    queryFn: () => wpClient.getTags(),
  });
}
```

### 5. 更新 `/root/.openclaw/workspace/cyberpress-platform/frontend/app/providers.tsx`
在现有 providers 中集成 ReactQueryProvider

```typescript
'use client';

import { ReactQueryProvider } from '@/lib/react-query';

export function Providers({ children }: { children: React.ReactNode }) {
  return <ReactQueryProvider>{children}</ReactQueryProvider>;
}
```

**任务说明：**
此任务将建立前端数据获取的基础设施，为后续将博客页面从 mock 数据迁移到真实 WordPress API 做准备。这是连接前后端的关键第一步。

## 当前状态

CyberPress Platform 是一个基于 WordPress + Next.js 的赛博朋克风格博客平台，项目进度约 85%。

**已完成部分：**
